css_snippet:
body {
  font-family: 'Merriweather', serif;
  font-size: 1.125rem; /* 18px base */
  line-height: 1.6;
}

h1 {
  font-family: 'Inter', sans-serif;
  font-size: 3rem;
  line-height: 1.15; /* Tighter for large headings */
  margin-bottom: 0.5em;
}

/* Responsive adjustment for larger screens */
@media (min-width: 768px) {
  body {
    font-size: 1.25rem; /* 20px on desktop */
    line-height: 1.65; /* Slightly more relaxed for wider lines */
  }
  h1 {
    font-size: 4rem;
    line-height: 1.1;
  }
}
